async function loadAll() {
  config = await window.petri.readConfig();
  latest = await window.petri.readLatest();
  runs = await window.petri.listRuns();
  if (!latest || Object.keys(latest).length === 0) status("No latest run found. Run a simulation.");
  renderAll();
}

async function runSimulation() {
  status("Running simulation...");
  $("runBtn").disabled = true;
  const args = { preset: $("preset").value, steps: $("steps").value, grid: $("grid").value };
  const res = await window.petri.run(args);
  $("runBtn").disabled = false;
  if (res.code !== 0) {
    status(`Run failed: ${res.stderr || res.stdout}`);
    return;
  }
  latest = res.latest || res.result || {};
  runs = await window.petri.listRuns();
  status(`Run complete: ${latest.run_id || "latest"}`);
  renderAll();
}

function installEvents() {
  ["fieldSelect","viewMode","cellDensity","cellScale","fieldOpacity","gridOverlay","halo","labels"].forEach(id => $(id).addEventListener("input", renderAll));
  $("runBtn").addEventListener("click", runSimulation);
  $("reloadBtn").addEventListener("click", loadAll);
  $("artifactBtn").addEventListener("click", () => window.petri.openArtifacts());

  const canvas = $("dishCanvas");
  canvas.addEventListener("wheel", (e) => {
    e.preventDefault();
    zoom *= e.deltaY < 0 ? 1.08 : 0.92;
    zoom = Math.max(.55, Math.min(3.2, zoom));
    drawDish();
  }, { passive: false });
  canvas.addEventListener("mousedown", (e) => { dragging = true; dragStart = { x: e.clientX - pan.x, y: e.clientY - pan.y }; });
  window.addEventListener("mouseup", () => dragging = false);
  window.addEventListener("mousemove", (e) => {
    if(!dragging) return;
    pan = { x: e.clientX - dragStart.x, y: e.clientY - dragStart.y };
    drawDish();
  });
  canvas.addEventListener("dblclick", () => { zoom = 1; pan = {x:0,y:0}; drawDish(); });
  window.addEventListener("resize", drawDish);
}

document.addEventListener("DOMContentLoaded", () => {
  installEvents();
  loadAll();
});

